# Solution: Error Logging and Monitoring

def create_error_log():
    """Return an empty list to serve as an error log."""
    return []

def log_error(error_log, error_type, message, context=""):
    """Append an error dict to the log and return the log."""
    error_log.append({
        "error_type": error_type,
        "message": message,
        "context": context
    })
    return error_log

def error_summary(error_log):
    """Return a dict with counts per error_type."""
    summary = {}
    for entry in error_log:
        t = entry["error_type"]
        summary[t] = summary.get(t, 0) + 1
    return summary

def recent_errors(error_log, n=5):
    """Return the last n entries from the log."""
    return error_log[-n:]
